package com.example.yourappname // Replace with your actual package name

import android.content.Context
import android.content.SharedPreferences

class AuthManager(context: Context) {

    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences(SHARED_PREFS_NAME, Context.MODE_PRIVATE)

    /**
     * Saves the authentication token and user ID to SharedPreferences.
     * Call this method upon successful user authentication.
     *
     * @param authToken The authentication token received from the server.
     * @param userId The unique identifier for the authenticated user.
     */
    fun saveAuthState(authToken: String, userId: String) {
        sharedPreferences.edit()
            .putString(KEY_AUTH_TOKEN, authToken)
            .putString(KEY_USER_ID, userId)
            .apply() // Use apply() for asynchronous saving
    }

    /**
     * Retrieves the saved authentication token.
     *
     * @return The authentication token, or null if not found.
     */
    fun getAuthToken(): String? {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null)
    }

    /**
     * Retrieves the saved user ID.
     *
     * @return The user ID, or null if not found.
     */
    fun getUserId(): String? {
        return sharedPreferences.getString(KEY_USER_ID, null)
    }

    /**
     * Checks if a user is currently logged in by verifying the presence
     * of both an authentication token and a user ID.
     *
     * @return True if both token and user ID are present and not empty, false otherwise.
     */
    fun isLoggedIn(): Boolean {
        return !getAuthToken().isNullOrEmpty() && !getUserId().isNullOrEmpty()
    }

    /**
     * Clears the saved authentication token and user ID, effectively logging out the user.
     */
    fun clearAuthState() {
        sharedPreferences.edit()
            .remove(KEY_AUTH_TOKEN)
            .remove(KEY_USER_ID)
            .apply() // Use apply() for asynchronous saving
    }

    companion object {
        // Name of the SharedPreferences file
        private const val SHARED_PREFS_NAME = "AuthPrefs"
        // Key for storing the authentication token
        private const val KEY_AUTH_TOKEN = "authToken"
        // Key for storing the user ID
        private const val KEY_USER_ID = "userId"
    }
}